def split_words(txt):
    '''
    Given a string of words, return a list of words split on whitespace. 
    If no whitespaces exist in the text, split on commas ','. 
    If no commas exist, return the number of lower-case letters with odd ordering in the alphabet.
    ord('a') = 0, ord('b') = 1, ..., ord('z') = 25.

    Examples:
    split_words("Hello world!") ➞ ["Hello", "world!"]
    split_words("Hello,world!") ➞ ["Hello", "world!"]
    split_words("abcdef") ➞ 3 
    '''

    # Check for whitespaces
    if ' ' in txt:
        return txt.split()

    # Check for commas
    elif ',' in txt:
        return txt.split(',')

    # Count lower-case letters with odd order in the alphabet
    else:
        return sum(1 for char in txt if char.islower() and (ord(char) - ord('a')) % 2 == 1)
