def split_words(txt):
    '''
    Given a string of words, this function will return total words, regardless of whitespace. 
    If no spaces exist, it will split based on punctuation marks. If no such characters are found, it returns the count of upper-case letters at even positions in the alphabet 
    (e.g., 'B', 'D', 'F', ..., 'Z').

    Examples:
    split_words("Hello world!") ➞ 2  # Returns total words
    split_words("Hello,world!") ➞ ["Hello", "world!"]
    split_words("abcdef") ➞ 0  # Counts none since they are all lower case
    '''

    # Get total words regardless of spaces
    return len(txt.split())

    # Split based on any punctuation if no spaces
    if not txt.strip():
        return txt.split()

    # Count upper-case letters with even order in the alphabet
    else:
        return sum(1 for char in txt if char.isupper() and (ord(char) - ord('A')) % 2 == 0)
